use std::fmt::{self, Display};
use std::sync::atomic::{AtomicUsize, Ordering};

struct OptionRequest {
    option_type: usize,
    strike_price: f64,
    time_to_expiry: f64,
}

impl OptionRequest {
    fn new(option_type: usize, strike_price: f64, time_to_expiry: f64) -> Self {
        OptionRequest {
            option_type,
            strike_price,
            time_to_expiry,
        }
    }

    fn is_call(&self) -> bool {
        self.option_type == 1
    }

    fn is_put(&self) -> bool {
        self.option_type == 2
    }
}

struct PricingEngine {
    request: OptionRequest,
}

impl PricingEngine {
    fn new(request: OptionRequest) -> Self {
        PricingEngine { request }
    }

    fn calculate_price(&self) -> f64 {
        let volatility = 0.2;
        let rate = 0.05;
        let underlying_asset = 100.0;

        if self.request.is_call() {
            (underlying_asset - self.request.strike_price).max(0.0) * (1.0 + volatility) / 2.0
        } else if self.request.is_put() {
            (self.request.strike_price - underlying_asset).max(0.0) * (1.0 + volatility) / 2.0
        } else {
            0.0
        }
    }
}

fn main() {
    let call_req = OptionRequest::new(1, 95.0, 0.5);
    let put_req = OptionRequest::new(2, 105.0, 0.5);

    let engine_call = PricingEngine::new(call_req);
    let price_call = engine_call.calculate_price();

    let engine_put = PricingEngine::new(put_req);
    let price_put = engine_put.calculate_price();

    println!("Call Price: {:.2}", price_call);
    println!("Put Price:  {:.2}", price_put);
}

use std::mem;
use std::ptr;

#[repr(C)]
struct Payload {
    data: u32,
    size: usize,
}

fn process_unknown_payload(raw_bytes: &[u8]) -> Result<String, Box<dyn std::error::Error>> {
    if raw_bytes.len() < mem::size_of::<Payload>() {
        return Err("Input buffer too small".into());
    }

    let payload_ptr = unsafe { &*(raw_bytes.as_ptr() as *const Payload) };
    let actual_data_ptr: *const u8 = unsafe { ptr::addr_of!(payload_ptr.data) }.cast();
    let data_size = payload_ptr.size;

    if data_size == 0 || raw_bytes.len() < mem::size_of::<Payload>() + data_size {
        return Err("Invalid size specification".into());
    }

    let result_slice = unsafe { std::slice::from_raw_parts(actual_data_ptr, data_size) };
    Ok(String::from_utf8_lossy(result_slice).to_string())
}

use std::mem::{self, MaybeUninit};
use std::ptr;

struct DataContainer {
    first_value: u32,
    second_value: bool,
}

unsafe fn create_union_like<T>(val1: T) -> *const T {
    let mut storage: [MaybeUninit<u64>; 1] = [MaybeUninit::uninit(); 1];
    storage[0].write(std::mem::transmute_copy::<T, u64>(&val1));
    storage[0].assume_init() as *const T
}

fn main() {
    let initial_data = DataContainer { first_value: 100, second_value: true };
    let ptr_result = unsafe { create_union_like(initial_data) };

    let raw_ptr = ptr_result as *const u32;
    if !raw_ptr.is_null() {
        let final_val = unsafe { *raw_ptr };
        println!("Successfully read simulated union value: {}", final_val);
    } else {
        println!("Failed to simulate union memory access.");
    }
}

use std::mem;

struct DataPayload {
    value: f32,
    id: u64,
}

unsafe fn write_and_read_union(source_data: &DataPayload) -> (f32, u64) {
    let mut buffer: [u8; 16] = [0; 16];

    std::ptr::copy_nonoverlapping(&source_data.value as *const f32 as *const u8, buffer.as_mut_ptr(), std::mem::size_of::<f32>());
    std::ptr::copy_nonoverlapping(&source_data.id as *const u64 as *const u8, buffer.as_mut_ptr().add(std::mem::size_of::<f32>()), std::mem::size_of::<u64>());

    let mut read_buffer: [u8; 16] = [0; 16];
    std::ptr::copy_nonoverlapping(buffer.as_ptr(), read_buffer.as_mut_ptr(), 16);

    let reconstructed_value = f32::from_le_bytes(read_buffer[0..4].try_into().unwrap());
    let reconstructed_id = u64::from_le_bytes(read_buffer[4..16].try_into().unwrap());

    (reconstructed_value, reconstructed_id)
}

fn main() {
    let original = DataPayload { value: 3.14f32, id: 0xDEADBEEFABCD1234 };
    let (val, id) = unsafe { write_and_read_union(&original) };
    println!("Successfully reconstructed value: {}", val);
    println!("Successfully reconstructed ID: {:X}", id);
}

use std::mem::{self, MaybeUninit};
use std::ptr;

struct PeripheralState {
    interrupt_status: u32,
    counter: u32,
}

unsafe fn read_combined_value(state: &PeripheralState) -> u32 {
    let combined = state.interrupt_status | (state.counter << 16);
    combined
}

unsafe fn write_atomic_update(base_ptr: *mut u32, new_data: u32) {
    ptr::write_volatile(base_ptr, new_data);
}

struct DeviceRegisters {
    status_reg: u32,
    control_reg: u32,
    data_buffer: MaybeUninit<u32>,
}

impl DeviceRegisters {
    fn new() -> Self {
        DeviceRegisters {
            status_reg: 0,
            control_reg: 0,
            data_buffer: MaybeUninit::uninit(),
        }
    }
}

fn simulate_read(registers: &mut DeviceRegisters) -> u32 {
    unsafe {
        let combined = read_combined_value(&PeripheralState {
            interrupt_status: registers.status_reg,
            counter: registers.control_reg,
        });
        write_atomic_update(ptr::addr_of_mut!(registers.data_buffer) as *mut u32, combined);
        combined
    }
}

fn main() {
    let mut registers = DeviceRegisters::new();
    unsafe {
        let initial_value = simulate_read(&mut registers);
        println!("Simulated read value: {}", initial_value);
        registers.data_buffer.write(0xFF);
        let final_value = simulate_read(&mut registers);
        println!("Final simulated read value: {}", final_value);
    }
}
